// test_config.cpp - Unit tests for git config parsing
// Tests GitConfig struct and observable parsing behavior

#include "test_harness.h"

// ============================================================================
// GitConfig Struct Tests
// ============================================================================

TEST(config_struct_layout) {
    GitConfig config = {};

    TEST_ASSERT_EQ(config.user_name[0], '\0');
    TEST_ASSERT_EQ(config.user_email[0], '\0');
    // Default should be False (0)
    TEST_ASSERT_EQ(config.core_autocrlf, GitConfig::AutoCRLF::False);
    TEST_ASSERT_FALSE(config.config_loaded);
}

TEST(config_autocrlf_values) {
    // AutoCRLF enum values: False=0, True=1, Input=2
    TEST_ASSERT_TRUE(GitConfig::AutoCRLF::True != GitConfig::AutoCRLF::False);
    TEST_ASSERT_TRUE(GitConfig::AutoCRLF::False != GitConfig::AutoCRLF::Input);
    TEST_ASSERT_TRUE(GitConfig::AutoCRLF::True != GitConfig::AutoCRLF::Input);
}

TEST(config_buffer_sizes) {
    GitConfig config;

    // Verify buffer sizes are reasonable (can store typical names/emails)
    TEST_ASSERT_TRUE(sizeof(config.user_name) >= 64);
    TEST_ASSERT_TRUE(sizeof(config.user_email) >= 128);
}

// ============================================================================
// Config Format Knowledge Tests
// ============================================================================

TEST(config_section_format) {
    // Git config sections: [section] or [section "subsection"]
    const char* user_section = "[user]";
    const char* core_section = "[core]";
    const char* remote_section = "[remote \"origin\"]";

    TEST_ASSERT_EQ(user_section[0], '[');
    TEST_ASSERT_EQ(core_section[0], '[');
    TEST_ASSERT_EQ(remote_section[0], '[');
}

TEST(config_key_value_format) {
    // Git config key = value format
    const char* name_line = "    name = John Doe";
    const char* email_line = "    email = john@example.com";

    // Keys are case-insensitive in git
    TEST_ASSERT_TRUE(strstr(name_line, "name") != nullptr);
    TEST_ASSERT_TRUE(strstr(email_line, "email") != nullptr);
}

TEST(config_comment_format) {
    // Git config comments: # or ;
    const char* hash_comment = "# This is a comment";
    const char* semi_comment = "; This is also a comment";

    TEST_ASSERT_EQ(hash_comment[0], '#');
    TEST_ASSERT_EQ(semi_comment[0], ';');
}

// ============================================================================
// Config Parsing Edge Cases (format understanding)
// ============================================================================

TEST(config_quoted_values) {
    // Git config can have quoted values: name = "John Doe"
    const char* quoted = "name = \"John Doe\"";
    const char* unquoted = "name = JohnDoe";

    // Quotes allow spaces in values
    TEST_ASSERT_TRUE(strstr(quoted, "\"") != nullptr);
    TEST_ASSERT_TRUE(strstr(unquoted, "\"") == nullptr);
}

TEST(config_multiline_values) {
    // Git config supports line continuation with backslash
    // This is format knowledge - our parser may or may not support this
    const char* continued = "message = first \\\n    second";
    TEST_ASSERT_TRUE(strstr(continued, "\\") != nullptr);
}

// ============================================================================
// Remote Config Format
// ============================================================================

TEST(config_remote_format) {
    // Remote config has url and fetch keys
    const char* remote_url = "    url = https://github.com/user/repo.git";
    const char* remote_fetch = "    fetch = +refs/heads/*:refs/remotes/origin/*";

    TEST_ASSERT_TRUE(strstr(remote_url, "url") != nullptr);
    TEST_ASSERT_TRUE(strstr(remote_fetch, "fetch") != nullptr);
}

// ============================================================================
// Branch Config Format
// ============================================================================

TEST(config_branch_format) {
    // Branch config has remote and merge keys
    const char* branch_remote = "    remote = origin";
    const char* branch_merge = "    merge = refs/heads/main";

    TEST_ASSERT_TRUE(strstr(branch_remote, "remote") != nullptr);
    TEST_ASSERT_TRUE(strstr(branch_merge, "merge") != nullptr);
}

// ============================================================================
// Complete Config File Format
// ============================================================================

TEST(config_full_format_knowledge) {
    // A typical .git/config structure
    const char* sample_config =
        "[core]\n"
        "    repositoryformatversion = 0\n"
        "    filemode = false\n"
        "    bare = false\n"
        "[user]\n"
        "    name = Test User\n"
        "    email = test@example.com\n"
        "[remote \"origin\"]\n"
        "    url = https://github.com/user/repo.git\n"
        "    fetch = +refs/heads/*:refs/remotes/origin/*\n";

    // Verify sections are present
    TEST_ASSERT_TRUE(strstr(sample_config, "[core]") != nullptr);
    TEST_ASSERT_TRUE(strstr(sample_config, "[user]") != nullptr);
    TEST_ASSERT_TRUE(strstr(sample_config, "[remote") != nullptr);
}
